  normalizeResizeValue,
  classifyResizeHint,
  resizeValueReg,
  normalizeExtensions,
  isHttpUrl,
  isProtocolRelativeUrl,
  isFileUrl,
  hasUrlScheme,
  hasSpecialScheme,
