    opt: currentOpt,
    imageBase,
    lidPattern,
    adjustedLmd,
    imgExtReg,
    resizeDataAttr,
    resizeOriginDataAttr,
    scaleSuffixDataAttr,
    outputSrcAttr,
    loadSrcResolver,
    loadSrcMap,
    loadSrcPrefixEntries,
    imageDir,
    hasImageDir,
    imageScale,
    imageScaleResizeValue,
    onImageProcessed,
